import React, { useState, useEffect } from "react";

import {
  TrendingUp, FileText, RefreshCw, Download, Brain, Loader
} from "lucide-react";
import { AlertCircle, Clock, Star, Check } from "lucide-react";

import Login from "./components/Login";
import Register from "./components/Register";

import Dashboard from "./components/Dashboard";
import Articles from "./components/Articles";
import Sources from "./components/Sources";
import DeckBuilder from "./components/DeckBuilder";
import AddSourceModal from "./components/AddSourceModal";

import { syncSources, getSources } from "./api";

// --- HARDCODE JWT FOR NOW (replace with actual logic or UI later) ---
const token = process.env.REACT_APP_JWT_TOKEN || "eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJzdWIiOiJzZWV0aGEiLCJ1c2VyX2lkIjoxLCJleHAiOjE3NTMyNjg0MDN9.PcS3-Zdg54v6IZIvCNTqCEI-E4v0YdkvmTDu-l7S1xk"

console.log("TOKEN as in App.js is:", token);

const App = () => {
  // --- Core state management ---
  const [activeTab, setActiveTab] = useState("dashboard");
  const [articles, setArticles] = useState([]);
  const [sources, setSources] = useState([]); // <-- all sources from backend
  const [selectedArticles, setSelectedArticles] = useState([]);
  const [filters, setFilters] = useState({
    dateRange: "30days",
    category: "all",
    source: "all",
    status: "all",
    relevanceMin: 0,
  });
  const [searchQuery, setSearchQuery] = useState("");
  const [showAddSource, setShowAddSource] = useState(false);
  const [editingNote, setEditingNote] = useState(null);
  const [notes, setNotes] = useState({});
  const [newSource, setNewSource] = useState({ name: "", url: "", type: "rss" });


  const [syncLimit, setSyncLimit] = useState(10);
  const [syncFromDate, setSyncFromDate] = useState(""); // format: YYYY-MM-DD
  const [syncing, setSyncing] = useState(false);


  // --- Load all sources from backend ---
  const fetchSources = async () => {
    try {
      const res = await getSources(token);
      setSources(res);
    } catch (err) {
      alert("Could not load sources: " + (err?.response?.data?.detail || err.message));
      setSources([]);
    }
  };

  useEffect(() => {
    fetchSources();
    // Optionally, also load articles here if you want (once backend supports it)
  }, []);

  // --- Handle SYNC Now ---
  const handleSync = async () => {
    setSyncing(true);
    try {
        await syncSources(token,{ limit: syncLimit, from_date: syncFromDate });
        await fetchSources();
        alert("Sync complete!");
    } catch (err) {
        alert("Sync failed: " + (err?.response?.data?.detail || err.message));
    }
    setSyncing(false);
  };


  // --- Status/Category Helpers (unchanged) ---
  const categories = [
    { id: "ai-finance", name: "AI Adoption in Finance", icon: require("lucide-react").Building2 },
    { id: "use-cases", name: "Gen AI Use Cases", icon: TrendingUp },
    { id: "agentic", name: "Agentic AI", icon: require("lucide-react").Brain },
    { id: "tech-corner", name: "Tech Corner", icon: require("lucide-react").Cpu },
    { id: "products", name: "Product Updates", icon: require("lucide-react").Users }
  ];
  const getStatusColor = (status) => {
    const colors = {
      new: "bg-gray-100 text-gray-700",
      reviewed: "bg-blue-100 text-blue-700",
      shortlisted: "bg-yellow-100 text-yellow-700",
      final: "bg-green-100 text-green-700",
    };
    return colors[status] || "bg-gray-100 text-gray-700";
  };
  const getStatusIcon = (status) => {
    const icons = {
      new: <AlertCircle className="w-4 h-4" />,
      reviewed: <Clock className="w-4 h-4" />,
      shortlisted: <Star className="w-4 h-4" />,
      final: <Check className="w-4 h-4" />
    };
    return icons[status] || null;
  };
  const handleStatusChange = (articleId, newStatus) => {
    setArticles(articles.map(article =>
      article.id === articleId ? { ...article, status: newStatus } : article
    ));
    if (newStatus === "final") {
      const article = articles.find(a => a.id === articleId);
      if (article && !selectedArticles.find(a => a.id === articleId)) {
        setSelectedArticles([...selectedArticles, article]);
      }
    } else {
      setSelectedArticles(selectedArticles.filter(a => a.id !== articleId));
    }
  };

  return (
    <div className="min-h-screen bg-gray-50">
      <header className="bg-white shadow-sm border-b">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex items-center justify-between h-16">
            <div className="flex items-center gap-3">
              <Brain className="w-8 h-8 text-blue-600" />
              <h1 className="text-xl font-bold text-gray-900">
                Gen AI Research Tool
              </h1>
            </div>
            <div className="flex items-center gap-4">
             <span className="text-sm text-gray-600">Research Division</span>
               <label>
                    # Articles:
                    <input
                    type="number"
                    value={syncLimit}
                    min={1}
                    max={100}
                    onChange={e => setSyncLimit(parseInt(e.target.value, 10))}
                    className="ml-2 px-2 py-1 border rounded w-20"
                    />
                </label>
                <label>
                    From date:
                    <input
                    type="date"
                    value={syncFromDate}
                    onChange={e => setSyncFromDate(e.target.value)}
                    className="ml-2 px-2 py-1 border rounded"
                    />
                </label>
                <button
                    onClick={handleSync}
                    className="px-4 py-2 bg-blue-600 text-white rounded"
                    disabled={syncing}
                >
                    {syncing ? "Syncing..." : "Sync Now"}
                </button>
            </div>
          </div>
        </div>
      </header>
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
        <nav className="flex space-x-8 mb-8 border-b">
          {[
            { id: "dashboard", label: "Dashboard", icon: TrendingUp },
            { id: "articles", label: "Articles", icon: FileText },
            { id: "sources", label: "Sources", icon: RefreshCw },
            { id: "deck-builder", label: "Deck Builder", icon: Download },
          ].map((tab) => {
            const Icon = tab.icon;
            return (
              <button
                key={tab.id}
                onClick={() => setActiveTab(tab.id)}
                className={`pb-4 px-1 border-b-2 font-medium text-sm flex items-center gap-2 transition-colors ${
                  activeTab === tab.id
                    ? "border-blue-500 text-blue-600"
                    : "border-transparent text-gray-500 hover:text-gray-700 hover:border-gray-300"
                }`}
              >
                <Icon className="w-4 h-4" />
                {tab.label}
              </button>
            );
          })}
        </nav>
        {activeTab === "dashboard" && (
          <Dashboard
            articles={articles}
            categories={categories}
            getStatusColor={getStatusColor}
          />
        )}
        {activeTab === "articles" && (
          <Articles
            articles={articles}
            setArticles={setArticles}
            filters={filters}
            setFilters={setFilters}
            searchQuery={searchQuery}
            setSearchQuery={setSearchQuery}
            selectedArticles={selectedArticles}
            setSelectedArticles={setSelectedArticles}
            editingNote={editingNote}
            setEditingNote={setEditingNote}
            notes={notes}
            setNotes={setNotes}
            getStatusColor={getStatusColor}
            getStatusIcon={getStatusIcon}
            handleStatusChange={handleStatusChange}
            categories={categories}
          />
        )}
        {activeTab === "sources" && (
          <Sources
            sources={sources}
            fetchSources={fetchSources}
            token={token}
          />
        )}
        {activeTab === "deck-builder" && (
          <DeckBuilder
            categories={categories}
            selectedArticles={selectedArticles}
            setSelectedArticles={setSelectedArticles}
            handleStatusChange={handleStatusChange}
          />
        )}
      </div>
      {/* If you want AddSourceModal as a separate popup, can integrate here */}
      {/* <AddSourceModal ... /> */}
    </div>
  );
};

export default App;
